const fs = require('fs');
const path = require('path');

// HTML correcto codificado en base64 para evitar problemas de encoding
const HTML_B64 = "";

const outPath = path.join(__dirname, 'docs', 'agustina-clavijo', 'index.html');

// Decodificar y escribir
const htmlContent = Buffer.from(HTML_B64, 'base64').toString('utf8');
fs.writeFileSync(outPath, htmlContent, {encoding: 'utf8'});

console.log('✅ HTML escrito:', htmlContent.length, 'bytes');
console.log('Verificando...');
const check = htmlContent.includes('x3C') && !htmlContent.includes('&quot;') && !htmlContent.includes('oninput=');
console.log(check ? '✅ Archivo correcto' : '❌ Algo falló');
